css:
/* Layout Containers */
.print-wrapper {
    width: 100%;
    display: flex;
    flex-direction: column;
    gap: 10px;
}

.section {
    padding: 10px;
}

.row-flex {
    display: flex;
    gap: 10px;
}

.col {
    display: flex;
    flex-direction: column;
}

.data-table {
    width: 100%;
    border-collapse: collapse;
    border: 1px solid black;
    font-size: 12px;
}

.data-table th, .data-table td {
    border: 1px solid black;
    /*padding: 5px;*/
    text-align: center;
}

.header { height: 60px; text-align: center; }
/*.sub-header { height: 30px; }*/
/*.items-section { min-height: 250px; }*/
.terms-table { font-size: 10px; }

.sign-table{
    border: none !important;
    /*border: 1px solid black !important;*/
    text-align: left;
}

.print-format td {padding: 4px !important}
